def introspect_token():
    """Token introspection endpoint (RFC 7662) - requires 'admin:tokens' scope."""
    data = request.get_json(silent=True)
    if not data or 'token' not in data:
        return jsonify({'active': False}), 200

    token_to_check = data['token']

    import re
    if not isinstance(token_to_check, str) or len(token_to_check) > 2048:
        return jsonify({'active': False}), 200

    if not re.match(r'^[A-Za-z0-9\-_\.]+$', token_to_check):
        return jsonify({'active': False}), 200

    check_hash = hash_token(token_to_check)
    token_record = AccessToken.query.filter_by(token_hash=check_hash).first()

    if token_record is None or not token_record.is_valid():
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'client_id': token_record.client_id,
        'scope': token_record.scopes,
        'exp': int(token_record.expires_at.replace(tzinfo=timezone.utc).timestamp()),
        'iat': int(token_record.created_at.replace(tzinfo=timezone.utc).timestamp()),
        'token_type': 'bearer'
    }), 200


